{
  "containerEnv": {
    "PW_CHROMIUM_SANDBOX": "0",
    "VSCODE_AGENT_FOLDER": "/vscode"
  },
  "remoteEnv": {
    "SSH_AUTH_SOCK": "/tmp/ssh-filter/agent.sock"
  },
  "customizations": {
    "vscode": {
      "settings": {
        "dev.containers.dockerCredentialHelper": false
      }
    }
  },
  "dockerComposeFile": ["docker-compose.yml"],
  "features": {
    // "ghcr.io/devcontainers-extra/features/lastpass-cli-homebrew:1": {}, -- broken, because ghcr.io no longer exists
    // "ghcr.io/devcontainers/features/aws-cli:1": {},
    // "ghcr.io/devcontainers/features/docker-outside-of-docker:1": {},
    // "ghcr.io/devcontainers/features/docker-in-docker:2": {},
    "ghcr.io/devcontainers/features/github-cli:1": {},
    "ghcr.io/devcontainers/features/node:1": {
      "version": "24"
    },
    "ghcr.io/devcontainers/features/python:1": {}
  },
  "forwardPorts": [3001],
  "portsAttributes": {},
  "init": true,
  "initializeCommand": ".devcontainer/host-scripts/initialize.sh",
  "mounts": [
    "source=/tmp/ssh-filter,target=/tmp/ssh-filter,type=bind,consistency=cached",
    "source=${localEnv:HOME}/.claude,target=/home/vscode/.claude,type=bind,consistency=cached",
    "source=${localEnv:HOME}/.claude.json,target=/home/vscode/.claude.json,type=bind,consistency=cached",
    "source=${localEnv:HOME}/.config/gh,target=/home/vscode/.config/gh,type=bind,consistency=cached"
  ],
  "name": "shardworks",
  "overrideCommand": true,
  "postAttachCommand": "/usr/local/bin/post-attach",
  "postCreateCommand": "/usr/local/bin/post-create",
  "remoteUser": "vscode",
  "service": "shardworks",
  "workspaceFolder": "/workspace"
}

